  function drawInsightCards(ctx, time, x, y, amount) {
    var cards = [
      ['Realtime', '42 streams', '#00D4FF'],
      ['Narrative', '6 scenes', '#F2AA4C'],
      ['Exports', '1080p MP4', '#7BD88F']
