    ctx.globalAlpha = amount;
    ctx.textAlign = 'center';
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 64px Arial, sans-serif';
    ctx.fillText('Depth Without Assets', width / 2, 134);
    ctx.fillStyle = '#C8D8EA';
    ctx.font = '25px Arial, sans-serif';
